params.script:
// ============================================================
// 電話番号フォーマット処理
// Brekeke PBX PAL/Designer - JavaScript ES5
// ============================================================

// ----------------------------------------------------------
// 1. モジュール結果の取得（Null安全）- 2ソース対応
// ----------------------------------------------------------
var rawInput1 = $runner.getModuleResult("phonenorm_入力_連絡先電話番号（聴取）");
var rawInput2 = $runner.getModuleResult("phonenorm_連絡先電話番号");

var rawStr1 = (rawInput1 !== null && rawInput1 !== undefined) ? String(rawInput1) : "";
var rawStr2 = (rawInput2 !== null && rawInput2 !== undefined) ? String(rawInput2) : "";

// ソース1優先、空の場合はソース2にフォールバック
var rawStr = (rawStr1.length > 0) ? rawStr1 : rawStr2;

// ----------------------------------------------------------
// 2. 数字のみ抽出
// ----------------------------------------------------------
var digitsOnly = "";
var i;
for (i = 0; i < rawStr.length; i++) {
    var ch = rawStr.charAt(i);
    if (ch >= "0" && ch <= "9") {
        digitsOnly = digitsOnly + ch;
    }
}

// ----------------------------------------------------------
// 3. 入力チェック（空の場合）
// ----------------------------------------------------------
if (digitsOnly.length === 0) {
    $runner.setResult("INVALID");
    throw "EXIT";
}

// ----------------------------------------------------------
// 4. 桁数チェックとフォーマット → setResult に直接出力
// ----------------------------------------------------------
var part1 = "";
var part2 = "";
var part3 = "";
var ttsPhone = "";

if (digitsOnly.length === 10) {
    // 固定電話：4桁・2桁・4桁
    part1 = digitsOnly.substring(0, 4);
    part2 = digitsOnly.substring(4, 6);
    part3 = digitsOnly.substring(6, 10);
    ttsPhone = part1 + "の" + part2 + "の" + part3;
    $runner.setResult(ttsPhone);
} else if (digitsOnly.length === 11) {
    // 携帯電話：3桁・4桁・4桁
    part1 = digitsOnly.substring(0, 3);
    part2 = digitsOnly.substring(3, 7);
    part3 = digitsOnly.substring(7, 11);
    ttsPhone = part1 + "の" + part2 + "の" + part3;
    $runner.setResult(ttsPhone);
} else {
    $runner.setResult("RETRY");
}

/**
 * 【Brekeke PBX Module Script】
 * 診察券番号抽出ロジック (有効性判定付き完全版)
 * Input:  入力_診察券番号
 * Output: medicalCardNumber (NUMBER) / 不明か未所持 / NO_RESULT
 */

// --- 1. 入力データ取得 ---
var rawInput = $runner.getModuleResult("入力_患者_診察券番号");
var text = "";
if (rawInput && typeof rawInput === "object" && rawInput.text) {
    text = String(rawInput.text);
} else if (typeof rawInput === "string") {
    text = rawInput;
}

// ── 無音 / TIMEOUT / 空白 → NO_RESULT ──
if (text.trim() === "" || text === "TIMEOUT" || text === "NO_RESULT") {
    $runner.setObject("medicalCardNumber", "NO_RESULT");
    $runner.setResult("NO_RESULT");
    return;
}

var result = "NO_RESULT";

// ─────────────────────────────────────────
// STEP 0: 有効性判定
// 意味のある発話かどうかチェック
// ─────────────────────────────────────────

/**
 * 有効な発話の条件:
 * 1. 数字を含む
 * 2. 日本語として意味のある単語を含む
 * 3. 上記どちらかに該当すればOK
 * → 雑音のみ (ザーザー/ノイズ) → NO_RESULT
 */
function isMeaningful(str) {
    // 数字が含まれる → 有効
    if (/[0-9０-９]/.test(str)) return true;

    // 意味のある日本語パターン
    // ひらがな2文字以上 or カタカナ2文字以上 or 漢字1文字以上
    if (/[ぁ-ん]{2,}/.test(str)) return true;   // ひらがな2文字以上
    if (/[ァ-ン]{2,}/.test(str)) return true;   // カタカナ2文字以上
    if (/[一-龥]/.test(str))     return true;   // 漢字1文字以上

    // アルファベット単語 (2文字以上)
    if (/[a-zA-Z]{2,}/.test(str)) return true;

    return false;
}

if (!isMeaningful(text)) {
    $runner.setObject("medicalCardNumber", "NO_RESULT");
    $runner.setResult("NO_RESULT");
    return;
}

// ─────────────────────────────────────────
// STEP 1: 不明・未所持・初診 判定 (最優先・部分一致)
// ─────────────────────────────────────────
var unknownWords = [
    // 不明・忘却
    "わからない","わかりません","わかんない","わからん",
    "分からない","分かりません","分からん",
    "不明","ふめい",
    "知らない","しらない","知りません","しりません",
    "覚えていない","おぼえていない","記憶にない",
    "忘れてしまった","忘れちゃいました","忘れちゃった","忘れた","わすれた",
    // 未所持
    "持っていませんでした","持ってませんでした",
    "持っていません","もっていません","持ってません","もってません",
    "持っていない","もっていない","持ってない","もってない",
    "診察券がない","診察券はない","診察券を持っていない",
    "手元にありません","手元にない",
    "ありませんでした","ありません",
    "なし","無い","ない",
    // 初診
    "まだ作っていない","まだ持っていない","まだない",
    "初めて来た","初めて受診","初めての予約",
    "はじめてです","初めてです","はじめて","初めて",
    "しょしん","初診です","初診"
];

var isUnknown = false;
for (var u = 0; u < unknownWords.length; u++) {
    if (text.indexOf(unknownWords[u]) !== -1) {
        isUnknown = true; break;
    }
}

if (isUnknown) {
    $runner.setObject("medicalCardNumber", "不明か未所持");
    $runner.setResult("不明か未所持");
    return;
}

// ─────────────────────────────────────────
// STEP 2: 数値正規化処理
// ─────────────────────────────────────────
var processed = text;

var replaceMap = [
    ["ゼロ","0"],["れい","0"],["まる","0"],["オー","0"],["おー","0"],["丸","0"],
    ["いち","1"],["ひと","1"],["ワン","1"],
    ["さん","3"],["サン","3"],
    ["よん","4"],
    ["ごー","5"],["Go","5"],["go","5"],
    ["ろく","6"],["ロク","6"],
    ["なな","7"],["しち","7"],["ナナ","7"],
    ["はち","8"],["ハチ","8"],
    ["きゅう","9"],["キュウ","9"],
    ["に","2"],["ニ","2"],
    ["し","4"],
    ["く","9"],
    ["ご","5"],
    ["一","1"],["二","2"],["三","3"],["四","4"],["五","5"],
    ["六","6"],["七","7"],["八","8"],["九","9"],["〇","0"],
    ["０","0"],["１","1"],["２","2"],["３","3"],["４","4"],
    ["５","5"],["６","6"],["７","7"],["８","8"],["９","9"],
    ["O","0"],["o","0"],["C","4"],["c","4"]
];

for (var r = 0; r < replaceMap.length; r++) {
    processed = processed.replace(
        new RegExp(replaceMap[r][0], "g"),
        replaceMap[r][1]
    );
}

// ─────────────────────────────────────────
// STEP 3: 数字のみ抽出・結合・判定
// ─────────────────────────────────────────
var digitsOnly = processed.replace(/[^0-9]/g, "");

if (digitsOnly.length >= 3) {
    result = digitsOnly;
} else {
    // 数字はあるが桁数不足 → NO_RESULT (再試行)
    result = "NO_RESULT";
}

// --- 2. 保存 ---
$runner.setObject("medicalCardNumber", result);

if (result !== "不明か未所持" && result !== "NO_RESULT") {
    try {
        var contextField = {
            contextName: "medicalCardNumber",
            displayType: "NUMBER",
            value: result
        };
        $ivr.exec("save2db", "save", JSON.stringify({ contextField: contextField }));
    } catch (e) { /* silent */ }
}

// --- 3. Branch遷移用 ---
$runner.setResult(result);
